 {\n  return axios.get(ReadBatch);\n}\n\nexport function ReadBatchByBranchIdData(id: any) {\n  return axios.get(readBatchById + id);\n}\n\nexport function UpdateBatchData(values: any) {\n  return axios.post(updateBatch, {\n    values,\n  });\n}\n\nexport function DeleteBatchData(id: any) {\n  return axios.get(deleteBatch + id);\n}\n","import clsx from \"clsx\";\nimport { useFormik } from \"formik\";\nimport { useState } from \"react\";\nimport { Modal } from \"react-bootstrap-v5\";\nimport Select from \"react-select\";\nimport UseAnimations from \"react-useanimations\";\nimport menu2 from \"react-useanimations/lib/menu2\";\nimport * as Yup from \"yup\";\nimport { UpdateBatchData } from \"../API/Batch_APIs\";\n\nconst validationSchema = Yup.object().shape({\n  batchStart: Yup.string().required(),\n  batchEnd: Yup.string().required(),\n  batchDuration: Yup.string().required(),\n});\n\nconst BatchCreateModal = (props: {\n  branchId: any;\n  setPageLoading: any;\n  show: Boolean;\n  onHide: any;\n}) => {\n  const [loading, setLoading] = useState(false);\n  const [showError, setshowError] = useState(false);\n  var initialValues: any = {\n    batchStart: \"\",\n    batchEnd: \"\",\n    batchDuration: \"\",\n    batchDurationType: \"Year\",\n    batchId: null,\n    instituteBranchIdDetails: [{ branchId: props.branchId }],\n    display: 1,\n  };\n\n  const formik = useFormik({\n    enableReinitialize: true,\n    initialValues,\n    validationSchema: validationSchema,\n    onSubmit: (values) => {\n      console.log(values);\n      setLoading(true);\n      try {\n        UpdateBatchData(values).then(() => {\n          props.onHide(false);\n          props.setPageLoading([\"true\"]);\n          formik.resetForm();\n          setLoading(false);\n        }).catch((error) => {\n          setshowError(true)\n        setLoading(false);\n        console.error(error);\n        formik.setSubmitting(false)\n        // window.location.replace(\"/error\");\n        });\n      } catch (error) {\n        setshowError(true)\n        setLoading(false);\n        console.error(error);\n        window.location.replace(\"/error\");\n      }\n      // setLoading(true);\n    },\n  });\n\n  const options = [\n    { value: \"Year\", label: \"Year\" },\n    { value: \"Month\", label: \"Month\" },\n  ];\n\n  const defaultOption = [{ value: \"Year\", label: \"Year\" }];\n\n  return (\n    <Modal {...props} aria-labelledby=\"contained-modal-title-vcenter\" centered>\n      <Modal.Header>\n        <Modal.Title>\n          <h1>Add Batch</h1>\n        </Modal.Title>\n        <div\n          className=\"btn btn-sm btn-icon btn-active-color-primary\"\n          onClick={props.onHide}\n        >\n          <UseAnimations\n            animation={menu2}\n            size={28}\n            strokeColor={\"#181C32\"}\n            reverse={true}\n          />\n        </div>\n      </Modal.Header>\n      <form\n        className=\"form w-100 fv-plugins-bootstrap5 fv-plugins-framework\"\n        onSubmit={formik.handleSubmit}\n      >\n        <Modal.Body>\n          <div className=\"modal-body\">\n            <div\n              className=\"scroll-y me-n7 pe-7\"\n              id=\"kt_modal_add_scroll\"\n              data-kt-scroll=\"true\"\n              data-kt-scroll-activate=\"{default: false, lg: true}\"\n              data-kt-scroll-max-height=\"auto\"\n              data-kt-scroll-dependencies=\"#kt_modal_add_header\"\n              data-kt-scroll-wrappers=\"#kt_modal_add_scroll\"\n              data-kt-scroll-offset=\"300px\"\n            >\n              <div className=\"fv-row mb-7\">\n                <label className=\"required fs-6 fw-bold mb-2\">\n                  Batch Start :\n                </label>\n\n                <input\n                  placeholder=\"Enter Batch Start\"\n                  type=\"text\"\n                  autoComplete=\"off\"\n                  {...formik.getFieldProps(\"batchStart\")}\n                  className={clsx(\n                    \"form-control form-control-lg form-control-solid\",\n                    {\n                      \"is-invalid text-danger\":\n                        formik.touched.batchStart && formik.errors.batchStart,\n                    },\n                    {\n                      \"is-valid\":\n                        formik.touched.batchStart && !formik.errors.batchStart,\n                    }\n                  )}\n                />\n                {formik.touched.batchStart && formik.errors.batchStart && (\n                  <div className=\"fv-plugins-message-container\">\n                    <div className=\"fv-help-block text-danger\">\n                      <span role=\"alert\">Batch Start is Required</span>\n                    </div>\n                  </div>\n                )}\n              </div>\n              <div className=\"fv-row mb-7\">\n                <label className=\"required fs-6 fw-bold mb-2\">\n                  Batch End :\n                </label>\n\n                <input\n                  placeholder=\"Enter Batch End\"\n                  type=\"text\"\n                  autoComplete=\"off\"\n                  {...formik.getFieldProps(\"batchEnd\")}\n                  className={clsx(\n                    \"form-control form-control-lg form-control-solid\",\n                    {\n                      \"is-invalid text-danger\":\n                        formik.touched.batchEnd && formik.errors.batchEnd,\n                    },\n                    {\n                      \"is-valid\":\n                        formik.touched.batchEnd && !formik.errors.batchEnd,\n                    }\n                  )}\n                />\n                {formik.touched.batchEnd && formik.errors.batchEnd && (\n                  <div className=\"fv-plugins-message-container\">\n                    <div className=\"fv-help-block text-danger\">\n                      <span role=\"alert\">Batch End is Required</span>\n                    </div>\n                  </div>\n                )}\n              </div>\n              <div className=\"fv-row mb-7\">\n                <label className=\"required fs-6 fw-bold mb-2\">\n                  Batch Duration :\n                </label>\n\n                <input\n                  placeholder=\"Enter Batch Duration\"\n                  type=\"number\"\n                  autoComplete=\"off\"\n                  {...formik.getFieldProps(\"batchDuration\")}\n                  className={clsx(\n                    \"form-control form-control-lg form-control-solid\",\n                    {\n                      \"is-invalid text-danger\":\n                        formik.touched.batchDuration &&\n                        formik.errors.batchDuration,\n                    },\n                    {\n                      \"is-valid\":\n                        formik.touched.batchDuration &&\n                        !formik.errors.batchDuration,\n                    }\n                  )}\n                />\n                {formik.touched.batchDuration && formik.errors.batchDuration && (\n                  <div className=\"fv-plugins-message-container\">\n                    <div className=\"fv-help-block text-danger\">\n                      <span role=\"alert\">Batch Duration is Required</span>\n                    </div>\n                  </div>\n                )}\n              </div>\n              <div className=\"fv-row mb-7\">\n                <label className=\"required fs-6 fw-bold mb-2\">\n                  Batch Duration Type :\n                </label>\n\n                <Select\n                  options={options}\n                  defaultValue={defaultOption}\n                  onChange={(data: any) => {\n                    formik.setFieldValue(\"batchDurationType\", data.value);\n                  }}\n                />\n              </div>\n            </div>\n          </div>\n        </Modal.Body>\n        <Modal.Footer>\n          <button\n            className=\"btn btn-sm btn-light btn-active-light-secoundary\"\n            onClick={props.onHide}\n          >\n            Close\n          </button>\n          {!showError && (\n          <button\n            type=\"submit\"\n            className=\"btn btn-sm btn-primary btn-active-light-secoundary\"\n            disabled={formik.isSubmitting || !formik.isValid}\n          >\n            {!loading && !showError && <span className=\"indicator-label\">Submit</span>}\n              {/* {loading && (\n                <span className=\"indicator-progress\" style={{ display: \"block\" }}>\n                  Please wait...{\" \"}\n                  <span className=\"spinner-border spinner-border-sm align-middle ms-2\"></span>\n                </span>\n              )} */}\n            \n          </button>\n          )}\n          {!loading && showError && (\n            <button\n            type=\"submit\"\n            className=\"btn btn-sm btn-danger btn-active-light-secoundary\"\n            disabled={formik.isSubmitting || !formik.isValid}\n            onClick={()=>{formik.handleSubmit()}}\n            >\n              <span className=\"indicator-label\">Error Happened</span>\n              </button>\n            )}\n        </Modal.Footer>\n      </form>\n    </Modal>\n  );\n};\n\nexport default BatchCreateModal;\n","import clsx from \"clsx\";\nimport { useFormik } from \"formik\";\nimport { useState } from \"react\";\nimport { Modal } from \"react-bootstrap-v5\";\nimport { useSearchParams } from \"react-router-dom\";\nimport Select from \"react-select\";\nimport UseAnimations from \"react-useanimations\";\nimport menu2 from \"react-useanimations/lib/menu2\";\nimport * as Yup from \"yup\";\nimport { UpdateBatchData } from \"../API/Batch_APIs\";\n\nconst validationSchema = Yup.object().shape({\n  batchStart: Yup.string().required(),\n  batchEnd: Yup.string().required(),\n  batchDuration: Yup.string().required(),\n});\n\nconst BatchEditModal = (props: {\n  show: Boolean;\n  onHide: any;\n  data: any;\n  setPageLoading: any;\n}) => {\n  const [loading, setLoading] = useState(false);\n\n  var initialValues: any = {\n    batchStart: props.data.instituteBatch.batchStart,\n    batchEnd: props.data.instituteBatch.batchEnd,\n    batchDuration: props.data.instituteBatch.batchDuration,\n    batchDurationType: props.data.instituteBatch.batchDurationType,\n    batchId: props.data.instituteBatch.batchId,\n    display: 1,\n  };\n  var [searchParams] = useSearchParams();\n  var branchId = searchParams.get(\"branchId\");\n  const formik = useFormik({\n    enableReinitialize: true,\n    initialValues,\n    validationSchema: validationSchema,\n    onSubmit: (values) => {\n      values.instituteBranchIdDetails = [{ branchId: branchId }];\n      try {\n        UpdateBatchData(values).then(() => {\n          props.onHide(false);\n          props.setPageLoading([\"true\"]);\n        });\n      } catch (error) {\n        console.error(error);\n        window.location.replace(\"/error\");\n      }\n      setLoading(true);\n    },\n  });\n\n  const options = [\n    { value: \"Year\", label: \"Year\" },\n    { value: \"Month\", label: \"Month\" },\n  ];\n\n  const optionsData = [\n    {\n      value: props.data.instituteBatch.batchDurationType,\n      label: props.data.instituteBatch.batchDurationType,\n    },\n  ];\n\n  return (\n    <Modal {...props} aria-labelledby=\"contained-modal-title-vcenter\" centered>\n      <Modal.Header>\n        <Modal.Title>\n          <h1>Edit Batch</h1>\n        </Modal.Title>\n        <div\n          className=\"btn btn-sm btn-icon btn-active-color-primary\"\n          onClick={props.onHide}\n        >\n          <UseAnimations\n            animation={menu2}\n            size={28}\n            strokeColor={\"#181C32\"}\n            reverse={true}\n          />\n        </div>\n      </Modal.Header>\n      <form\n        className=\"form w-100 fv-plugins-bootstrap5 fv-plugins-framework\"\n        onSubmit={formik.handleSubmit}\n      >\n        <Modal.Body>\n          <div className=\"modal-body\">\n            <div\n              className=\"scroll-y me-n7 pe-7\"\n              id=\"kt_modal_add_scroll\"\n              data-kt-scroll=\"true\"\n              data-kt-scroll-activate=\"{default: false, lg: true}\"\n              data-kt-scroll-max-height=\"auto\"\n              data-kt-scroll-dependencies=\"#kt_modal_add_header\"\n              data-kt-scroll-wrappers=\"#kt_modal_add_scroll\"\n              data-kt-scroll-offset=\"300px\"\n            >\n              <div className=\"fv-row mb-7\">\n                <label className=\"required fs-6 fw-bold mb-2\">\n                  Batch Start :\n                </label>\n\n                <input\n                  placeholder=\"Enter Batch Start\"\n                  type=\"text\"\n                  autoComplete=\"off\"\n                  {...formik.getFieldProps(\"batchStart\")}\n                  className={clsx(\n                    \"form-control form-control-lg form-control-solid\",\n                    {\n                      \"is-invalid text-danger\":\n                        formik.touched.batchStart && formik.errors.batchStart,\n                    },\n                    {\n                      \"is-valid\":\n                        formik.touched.batchStart && !formik.errors.batchStart,\n                    }\n                  )}\n                />\n                {formik.touched.batchStart && formik.errors.batchStart && (\n                  <div className=\"fv-plugins-message-container\">\n                    <div className=\"fv-help-block text-danger\">\n                      <span role=\"alert\">Batch Start is Required</span>\n                    </div>\n                  </div>\n                )}\n              </div>\n              <div className=\"fv-row mb-7\">\n                <label className=\"required fs-6 fw-bold mb-2\">\n                  Batch End :\n                </label>\n\n                <input\n                  placeholder=\"Enter Batch End\"\n                  type=\"text\"\n                  autoComplete=\"off\"\n                  {...formik.getFieldProps(\"batchEnd\")}\n                  className={clsx(\n                    \"form-control form-control-lg form-control-solid\",\n                    {\n                      \"is-invalid text-danger\":\n                        formik.touched.batchEnd && formik.errors.batchEnd,\n                    },\n                    {\n                      \"is-valid\":\n                        formik.touched.batchEnd && !formik.errors.batchEnd,\n                    }\n                  )}\n                />\n                {formik.touched.batchEnd && formik.errors.batchEnd && (\n                  <div className=\"fv-plugins-message-container\">\n                    <div className=\"fv-help-block text-danger\">\n                      <span role=\"alert\">Batch End is Required</span>\n                    </div>\n                  </div>\n                )}\n              </div>\n              <div className=\"fv-row mb-7\">\n                <label className=\"required fs-6 fw-bold mb-2\">\n                  Batch Duration :\n                </label>\n\n                <input\n                  placeholder=\"Enter Batch Duration\"\n                  type=\"number\"\n                  autoComplete=\"off\"\n                  {...formik.getFieldProps(\"batchDuration\")}\n                  className={clsx(\n                    \"form-control form-control-lg form-control-solid\",\n                    {\n                      \"is-invalid text-danger\":\n                        formik.touched.batchDuration &&\n                        formik.errors.batchDuration,\n                    },\n                    {\n                      \"is-valid\":\n                        formik.touched.batchDuration &&\n                        !formik.errors.batchDuration,\n                    }\n                  )}\n                />\n                {formik.touched.batchDuration && formik.errors.batchDuration && (\n                  <div className=\"fv-plugins-message-container\">\n                    <div className=\"fv-help-block text-danger\">\n                      <span role=\"alert\">Batch Duration is Required</span>\n                    </div>\n                  </div>\n                )}\n              </div>\n              <div className=\"fv-row mb-7\">\n                <label className=\"required fs-6 fw-bold mb-2\">\n                  Batch Duration Type :\n                </label>\n\n                <Select\n                  options={options}\n                  defaultValue={optionsData}\n                  onChange={(data: any) => {\n                    formik.setFieldValue(\"batchDurationType\", data.value);\n                  }}\n                />\n              </div>\n            </div>\n          </div>\n        </Modal.Body>\n        <Modal.Footer>\n          <button\n            className=\"btn btn-sm btn-light btn-active-light-secoundary\"\n            onClick={props.onHide}\n          >\n            Close\n          </button>\n          <button\n            type=\"submit\"\n            id=\"kt_sign_up_submit\"\n            className=\"btn btn-sm btn-primary btn-active-light-secoundary\"\n            disabled={formik.isSubmitting || !formik.isValid}\n          >\n            {!loading && <span className=\"indicator-label\">Submit</span>}\n            {loading && (\n              <span className=\"indicator-progress\" style={{ display: \"block\" }}>\n                Please wait...{\" \"}\n                <span className=\"spinner-border spinner-border-sm align-middle ms-2\"></span>\n              </span>\n            )}\n          </button>\n        </Modal.Footer>\n      </form>\n    </Modal>\n  );\n};\n\nexport default BatchEditModal;\n","import { MDBDataTableV5 } from \"mdbreact\";\nimport { useState } from \"react\";\nimport { Link } from \"react-router-dom\";\nimport UseAnimations from \"react-useanimations\";\nimport trash from \"react-useanimations/lib/trash\";\nimport { ActionIcon } from \"../../../components/ActionIcon\";\nimport { DeleteBatchData } from \"../API/Batch_APIs\";\nimport BatchEditModal from \"./BatchEditModal\";\n\nconst BatchTable = (props: {\n  data: any;\n  setLoading: any;\n  setPageLoading: any;\n}) => {\n  const [modalShowEdit, setModalShowEdit] = useState(false);\n  const [editModalData, setEditModalData] = useState({\n    instituteBatch: {\n      batchStart: \"\",\n      batchEnd: \"\",\n      batchDuration: \"\",\n      batchDurationType: \"\",\n      batchId: \"\",\n      branchId: \"\",\n    },\n    instituteBranch: \"\",\n  });\n\n  const datatable = {\n    columns: [\n      {\n        label: \"Start\",\n        field: \"batchStart\",\n        width: 100,\n        attributes: {\n          \"aria-controls\": \"DataTable\",\n          \"aria-label\": \"Name\",\n        },\n      },\n      {\n        label: \"End\",\n        field: \"batchEnd\",\n        sort: \"asc\",\n        width: 100,\n      },\n      {\n        label: \"Duration\",\n        field: \"batchDuration\",\n        sort: \"asc\",\n        width: 100,\n      },\n      {\n        label: \"Duration Type\",\n        field: \"batchDurationType\",\n        sort: \"asc\",\n        width: 100,\n      },\n      {\n        label: \"Actions\",\n        field: \"actions\",\n        sort: \"disabled\",\n        width: 150,\n      },\n    ],\n\n    rows: props.data.map((data) =>\n      data.instituteBatch.display === true\n        ? {\n            batchStart: data.instituteBatch.batchStart,\n            batchEnd: data.instituteBatch.batchEnd,\n            batchDuration: data.instituteBatch.batchDuration,\n            batchDurationType: data.instituteBatch.batchDurationType,\n            actions: (\n              <>\n                <button\n                  onClick={() => {\n                    setEditModalData(data);\n                    setModalShowEdit(true);\n                  }}\n                  className=\"btn btn-icon btn-primary btn-sm me-3\"\n                >\n                  <ActionIcon type=\"edit\" size=\"sm\" />\n                </button>\n\n                <button\n                  onClick={() => {\n                    props.setLoading(true);\n                    DeleteBatchData(data.instituteBatch.batchId).then(() => {\n                      props.setPageLoading([\"true\"]);\n                    });\n                  }}\n                  className=\"btn btn-icon btn-danger btn-sm me-3\"\n                >\n                  <UseAnimations\n                    animation={trash}\n                    size={22}\n                    strokeColor={\"#EFF8FE\"}\n                  />\n                </button>\n\n                <Link\n                  to=\"/session\"\n                  state={{\n                    batchId: data.instituteBatch.batchId,\n                    batchStart: data.instituteBatch.batchStart,\n                    batchEnd: data.instituteBatch.batchEnd,\n                  }}\n                  className=\"btn btn-sm btn-info\"\n                >\n                  Add Session\n                </Link>\n              </>\n            ),\n          }\n        : {}\n    ),\n  };\n\n  return (\n    <>\n      <MDBDataTableV5\n        hover\n        scrollY\n        maxHeight=\"160vh\"\n        entriesOptions={[5, 20, 25]}\n        entries={25}\n        pagesAmount={4}\n        data={datatable}\n      />\n      <BatchEditModal\n        show={modalShowEdit}\n        onHide={() => setModalShowEdit(false)}\n        data={editModalData}\n        setPageLoading={props.setPageLoading}\n      />\n    </>\n  );\n};\n\nexport default BatchTable;\n","import { useEffect, useState } from \"react\";\nimport { Button } from \"react-bootstrap\";\nimport { IconContext } from \"react-icons\";\nimport { BiBookReader } from \"react-icons/bi\";\nimport { useLocation } from \"react-router-dom\";\nimport { ReadBatchByBranchIdData } from \"./API/Batch_APIs\";\nimport BatchCreateModal from \"./components/BatchCreateModal\";\nimport BatchTable from \"./components/BatchTable\";\n\nconst BatchPage = () => {\n  const [modalShowCreate, setModalShowCreate] = useState(false);\n  const [BatchData, setBatchData] = useState([]);\n  const [loading, setLoading] = useState(false);\n  const [pageLoading, setPageLoading] = useState([\"false\"]);\n  const location = useLocation();\n  const data: any = location.state;\n\n  useEffect(() => {\n    setLoading(true);\n    try {\n      ReadBatchByBranchIdData(data.branchId).then((data) => {\n        setBatchData(data.data.instituteBranchBatchMapping);\n        setLoading(false);\n      });\n    } catch (error) {\n      console.error(error);\n      window.location.replace(\"/error\");\n    }\n  }, [pageLoading]);\n\n  return (\n    <div className=\"card\">\n      {loading && (\n        <span className=\"indicator-progress m-5\" style={{ display: \"block\" }}>\n          Please wait...{\" \"}\n          <span className=\"spinner-border spinner-border-sm align-middle ms-2\"></span>\n        </span>\n      )}\n\n      {!loading && (\n        <div className=\"card-header border-0 pt-6\">\n          <div className=\"card-title\">\n            <h1>{data.branch} - Batches</h1>\n          </div>\n\n          <div className=\"card-toolbar\">\n            <div className=\"d-flex justify-content-end\">\n              <Button\n                variant=\"primary\"\n                onClick={() => {\n                  setModalShowCreate(true);\n                }}\n              >\n                <IconContext.Provider\n                  value={{ style: { paddingBottom: \"4px\" } }}\n                >\n                  <div>\n                    Add Batch <BiBookReader size={23} />\n                  </div>\n                </IconContext.Provider>\n              </Button>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {!loading && (\n        <div className=\"card-body pt-5\">\n          <BatchTable\n            data={BatchData}\n            setLoading={setLoading}\n            setPageLoading={setPageLoading}\n          />\n        </div>\n      )}\n\n      <BatchCreateModal\n        branchId={data.branchId}\n        setPageLoading={setPageLoading}\n        show={modalShowCreate}\n        onHide={() => setModalShowCreate(false)}\n      />\n    </div>\n  );\n};\n\nexport default BatchPage;\n"],"names":["API_URL","process","readBatchById","concat","updateBatch","deleteBatch","UpdateBatchData","values","axios","validationSchema","Yup","shape","batchStart","required","batchEnd","batchDuration","components_BatchCreateModal","props","_useState","useState","_useState2","_slicedToArray","loading","setLoading","_useState3","_useState4","showError","setshowError","initialValues","batchDurationType","batchId","instituteBranchIdDetails","branchId","display","formik","useFormik","enableReinitialize","onSubmit","console","log","then","onHide","setPageLoading","resetForm","catch","error","setSubmitting","window","location","replace","_jsxs","Modal","_objectSpread","centered","children","_jsx","className","onClick","UseAnimations","animation","menu2","size","strokeColor","reverse","handleSubmit","id","placeholder","type","autoComplete","getFieldProps","clsx","touched","errors","role","Select","options","value","label","defaultValue","onChange","data","setFieldValue","disabled","isSubmitting","isValid","components_BatchEditModal","instituteBatch","_useSearchParams","useSearchParams","get","optionsData","style","components_BatchTable","modalShowEdit","setModalShowEdit","instituteBranch","editModalData","setEditModalData","datatable","columns","field","width","attributes","sort","rows","map","actions","_Fragment","ActionIcon","trash","Link","to","state","MDBDataTableV5","hover","scrollY","maxHeight","entriesOptions","entries","pagesAmount","BatchEditModal","show","Batch_BatchPage","BatchPage","